package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatWithHeaderTest {

    private enum TestEnum {
        FIRST, SECOND, THIRD
    }

    private enum EmptyEnum {}

    @Test
    void withHeader_withNullEnum_returnsCSVFormatWithNullHeader() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Cast null to Class<? extends Enum<?>> to avoid ambiguous call
        CSVFormat result = format.withHeader((Class<? extends Enum<?>>) null);
        assertNotNull(result);
        assertNull(result.getHeader());
    }

    @Test
    void withHeader_withEmptyEnum_returnsCSVFormatWithEmptyHeader() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeader(EmptyEnum.class);
        assertNotNull(result);
        assertArrayEquals(new String[0], result.getHeader());
    }

    @Test
    void withHeader_withEnum_returnsCSVFormatWithEnumNamesAsHeader() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeader(TestEnum.class);
        assertNotNull(result);
        String[] expected = {"FIRST", "SECOND", "THIRD"};
        assertArrayEquals(expected, result.getHeader());
    }
}
